// Normalize input from webhook or Execute Workflow trigger
const body = $input.first().json.body || $input.first().json;
const task = body.task || body.message || 'No task provided';
const priority = body.priority || 'normal';
const requestedBy = body.requestedBy || 'mcp';
const retryCount = body._retryCount || 0;
const parentLogId = body._parentLogId || null;

return [{ json: { task, priority, requestedBy, retryCount, parentLogId, startTime: Date.now() } }];

// Pass through — logging will be done after completion
const prev = $input.first().json;
return [{ json: { ...prev, logId: null, startTime: Date.now() } }];

