const prev = $('Prepare Task').first().json;
const VALID = ['clients', 'marketing', 'operations', 'content', 'finance'];
const DEFAULT_CATEGORY = 'clients';

try {
  const raw = $input.first().json.content[0].text;
  // Strip markdown fences, whitespace, and any leading text before {
  let cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const braceStart = cleaned.indexOf('{');
  const braceEnd = cleaned.lastIndexOf('}');
  if (braceStart >= 0 && braceEnd > braceStart) {
    cleaned = cleaned.substring(braceStart, braceEnd + 1);
  }
  const decision = JSON.parse(cleaned);

  // STRICT VALIDATION: category must be one of the 5 allowed values
  let category = (decision.category || '').toString().toLowerCase().trim();
  if (!VALID.includes(category)) {
    // Try to infer from keywords in the raw response
    const rawLower = raw.toLowerCase();
    category = VALID.find(v => rawLower.includes(v)) || DEFAULT_CATEGORY;
  }

  const confidence = Math.min(100, Math.max(0, parseInt(decision.confidence) || 80));
  const reason = decision.reason || decision.reasoning || 'classified by AI';

  return [{ json: {
    ...prev,
    category,
    confidence,
    reason,
    workflow: category,
    parameters: decision.parameters || {},
    next_tasks: decision.next_tasks || [],
    _parseOk: true
  } }];
} catch (e) {
  // FALLBACK: if Claude response is completely unparseable, default to clients
  const rawText = ($input.first().json.content?.[0]?.text || '').toLowerCase();
  const VALID_CHECK = ['clients', 'marketing', 'operations', 'content', 'finance'];
  const inferred = VALID_CHECK.find(v => rawText.includes(v)) || DEFAULT_CATEGORY;

  return [{ json: {
    ...prev,
    category: inferred,
    confidence: 40,
    reason: 'PARSE_FALLBACK: ' + e.message + ' — inferred: ' + inferred,
    workflow: inferred,
    parameters: {},
    next_tasks: [],
    _parseOk: false,
    _rawResponse: ($input.first().json.content?.[0]?.text || '').substring(0, 500)
  } }];
}

// === EVALUATE RESULT + AGENT LOOP LOGIC ===
const decision = $('Parse Decision').first().json;
const execResult = $input.first().json || {};
const elapsed = Date.now() - (decision.startTime || Date.now());

// Detect errors: explicit error fields OR n8n continueOnError metadata
const hasError = execResult.status === 'error' || execResult.error || execResult.errorMessage || (execResult.$error && true);
const errorMsg = execResult.errorMessage || execResult.error || (execResult.$error ? execResult.$error.message : null);
const status = hasError ? 'failed' : 'completed';

const nextTasks = decision.next_tasks || [];
const hasNextTask = nextTasks.length > 0 && !hasError;

return [{ json: {
  status,
  agent_version: '3.1',
  log_id: decision.logId,
  task: decision.task,
  workflow_executed: decision.workflow,
  category: decision.category,
  confidence: decision.confidence,
  reasoning: decision.reason,
  parameters: decision.parameters,
  result: hasError ? { error: errorMsg || 'Sub-workflow execution failed', raw: execResult } : execResult,
  execution_time_ms: elapsed,
  has_next_task: hasNextTask,
  next_tasks: nextTasks,
  retry_count: decision.retryCount || 0,
  _shouldRetry: false,
  _nextRetryCount: (decision.retryCount || 0) + 1,
  completedAt: new Date().toISOString()
} }];

// === AGENT LOOP: decide next action ===
const evaluation = $('Evaluate Result').first().json;

if (evaluation._shouldRetry) {
  return [{ json: {
    _action: 'retry',
    task: evaluation.task,
    _retryCount: evaluation._nextRetryCount,
    _parentLogId: evaluation.log_id,
    message: 'Retrying (attempt ' + evaluation._nextRetryCount + '/3)...'
  } }];
}

if (evaluation.has_next_task && evaluation.next_tasks.length > 0) {
  return [{ json: {
    _action: 'next_task',
    task: evaluation.next_tasks[0],
    remaining_tasks: evaluation.next_tasks.slice(1),
    _parentLogId: evaluation.log_id,
    previous_result: evaluation.result
  } }];
}

return [{ json: {
  _action: 'done',
  status: evaluation.status,
  agent_version: evaluation.agent_version,
  log_id: evaluation.log_id,
  task: evaluation.task,
  workflow_executed: evaluation.workflow_executed,
  category: evaluation.category,
  confidence: evaluation.confidence,
  reasoning: evaluation.reasoning,
  result: evaluation.result,
  execution_time_ms: evaluation.execution_time_ms,
  next_tasks: evaluation.next_tasks,
  completedAt: evaluation.completedAt
} }];

// This should now RARELY fire — Parse Decision always returns a valid category
const decision = $('Parse Decision').first().json;
return [{ json: {
  status: 'error',
  agent_version: '3.1',
  error: 'no_matching_category',
  message: 'Category "' + decision.category + '" did not match any route. This indicates a bug in Parse Decision fallback logic.',
  task: decision.task,
  parsed_category: decision.category,
  confidence: decision.confidence,
  reason: decision.reason,
  _parseOk: decision._parseOk,
  _rawResponse: decision._rawResponse || null
} }];
